import{_ as a}from"./chunks/placeholder.DuiHaLuQ.js";import{_ as t,o as s,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/media/202212/2022-12-31_184323_5037510.7973227221018393.png",b=JSON.parse('{"title":"设备人设开发","description":"","frontmatter":{"title":"设备人设开发"},"headers":[],"relativePath":"custom-biz/device-persona.md","filePath":"custom-biz/device-persona.md","lastUpdated":null}'),p={name:"custom-biz/device-persona.md"};function o(l,e,c,d,h,m){return s(),r("div",null,[...e[0]||(e[0]=[n(`<h2 id="什么是设备人设" tabindex="-1">什么是设备人设 <a class="header-anchor" href="#什么是设备人设" aria-label="Permalink to &quot;什么是设备人设&quot;">​</a></h2><p>通过配置年龄，性别等属性值与回复语，让产品拟人化。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户：你多大了？</span></span>
<span class="line"><span>AIUI：我今年6岁</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="创建设备人设" tabindex="-1">创建设备人设 <a class="header-anchor" href="#创建设备人设" aria-label="Permalink to &quot;创建设备人设&quot;">​</a></h2><p>在技能工作室的<a href="https://aiui.xfyun.cn/studio/character" target="_blank" rel="noreferrer">【设备人设】</a>中创建。</p><p><img src="`+a+'" alt="待补充：技能工作室控制台截图"></p><p>默认人设<strong>蓝小飞</strong>不可删除，用户可在“蓝小飞”基础上编辑，也可以新建人设。新建人设的属性值默认开启且为空。</p><h3 id="属性值与回复" tabindex="-1">属性值与回复 <a class="header-anchor" href="#属性值与回复" aria-label="Permalink to &quot;属性值与回复&quot;">​</a></h3><p>设备人设有46种属性，分类为基础信息，联系方式，社会关系等。我们为每种属性配置了系统问法与回复。其中问法由AIUI定义，在页面中只展示了3种示例问法，回复则分为两种情况，<strong>属性值为空或非空</strong>：</p><p><img src="'+a+'" alt="待补充：设备人设空值属性截图"></p><p><img src="'+a+'" alt="待补充：设备人设属性值配置截图"></p><p>如上图，当姓名的属性值为空时，系统回复：“这可是个秘密哦”；当属性值非空时，则会将属性值以参数的形式带入系统回复之中：“我叫{name}，是你的家庭小助理”等等，这里的{name}值=“小叮当”。需要注意的是，这里的系统回复也只展示3条示例回复，实际回复不止这些，当用户语料命中人设后，系统将会从众多的系统回复中随机返回一条给用户。</p><p>若系统回复不能满足开发者的个性化需求，可以采用<strong>自定义回复</strong>的形式。自定义回复不支持参数，只支持文本。</p><p>每个属性最多30条自定义回复，每条回复最多100字符。</p><h3 id="输入建议" tabindex="-1">输入建议 <a class="header-anchor" href="#输入建议" aria-label="Permalink to &quot;输入建议&quot;">​</a></h3><p>部分属性支持多个值，用空格键分隔</p><p>部分属性有关联关系，如果在【生日】属性中选择【具体日期】，系统会自动算出【年龄】【星座】【生肖】。</p><h2 id="使用设备人设" tabindex="-1">使用设备人设 <a class="header-anchor" href="#使用设备人设" aria-label="Permalink to &quot;使用设备人设&quot;">​</a></h2><p>设备人设默认关闭，引用步骤：【我的应用】-【应用配置】-【语义理解】-【管理技能配置】-【设备人设】</p><p><img src="'+i+'" alt="" title="null"></p><p>设备人设优先级：自定义技能&gt;自定义问答&gt;设备人设&gt;商店技能</p>',21)])])}const g=t(p,[["render",o]]);export{b as __pageData,g as default};
